# ---------------------------------------------------------------------------
# TimeOfDay
# ---------------------------------------------------------------------------

class TimeOfDay(Enum):
    """Simple enumeration used to determine the part of the day."""

    MORNING = "Morning"
    AFTERNOON = "Afternoon"
    EVENING = "Evening"

    @staticmethod
    def of(hour: int) -> "TimeOfDay":
        """Map an hour (0–23) to the appropriate :class:`TimeOfDay`."""
        if hour < 12:
            return TimeOfDay.MORNING
        if hour < 17:
            return TimeOfDay.AFTERNOON
        return TimeOfDay.EVENING


# ---------------------------------------------------------------------------
# season_of
# ---------------------------------------------------------------------------

def season_of(month: int) -> str:
    """Return the meteorological season for the given month number (1–12)."""
    if month in (12, 1, 2):
        return "Winter"
    if month in (3, 4, 5):
        return "Spring"
    if month in (6, 7, 8):
        return "Summer"
    return "Autumn"


