def main() -> None:
    """Entry point – prints a greeting and today's date information."""
    today = date.today()
    hour = datetime.now().hour

    salutation_map = {
        TimeOfDay.MORNING: "Good morning",
        TimeOfDay.AFTERNOON: "Good afternoon",
        TimeOfDay.EVENING: "Good evening",
    }
    salutation = salutation_map[TimeOfDay.of(hour)]
    greeting = Greeting("World", salutation)

    sys.stdout.write(greeting.formatted())

    info = (
        f"Python version : {sys.version}\n"
        f"Today's date   : {today} ({season_of(today.month)})\n"
    )
    sys.stdout.write(info)


if __name__ == "__main__":
    main()
